func TestBearerTokenFromHeader(t *testing.T) {
	tests := []struct {
		name   string
		header string
		token  string
		ok     bool
	}{
		{"valid bearer", "Bearer abc123", "abc123", true},
		{"valid bearer with spaces", "Bearer   abc.def.ghi  ", "abc.def.ghi", true},
		{"lowercase bearer", "bearer xyz", "xyz", true},
		{"all uppercase", "BEARER xyz", "xyz", true},
		{"empty", "", "", false},
		{"no prefix", "abc123", "", false},
		{"basic auth", "Basic dXNlcjpwYXNz", "", false},
		{"only bearer prefix no token", "Bearer ", "", false},
		{"bearer prefix exactly", "Bearer", "", false},
		{"malformed", "Bear abc", "", false},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			token, ok := bearerTokenFromHeader(tt.header)
			if ok != tt.ok {
				t.Errorf("ok: got %v, want %v", ok, tt.ok)
			}
			if token != tt.token {
				t.Errorf("token: got %q, want %q", token, tt.token)
			}
		})
	}
}

